import React from 'react'
import { Link } from 'gatsby'
import { styled, css } from 'styled-components'

const PageContainer = styled.div`
    width: 100%;
    height: 100%;
    display: grid;
    place-items: center;
`

const ProjectGrid = styled.div`
    max-width: 1200px;
    display: grid;
    row-gap: 1rem;
    column-gap: 1rem;
    padding: 1rem;

    @media screen and (min-width: 768px) {
        grid-template-rows: auto auto;
        grid-template-columns: repeat(4, auto);
    }
`

const CardBase = css`
    border: 1px solid rgb(60, 60, 60);
    border-radius: 1rem;
    padding: 1rem;
    background-color: rgb(30, 30, 30);
    text-decoration: none;
    cursor: pointer;
    transition: opacity 250ms;

    &:visited {
        color: inherit;
    }

    &:hover {
        opacity: 0.7;
    }

    & h1 {
        margin: 0 0 1rem 0;
        font-weight: normal;
    }

    & p {
        margin: 0;
        color: rgb(215, 215, 215);
    }
`

const Card = styled.div`
    ${CardBase}
`

const AnchoredCard = styled.a`
    ${CardBase}
`

const LinkedCard = styled(Link)`
    ${CardBase}
`

const HorizontalCard = styled(LinkedCard)`
    @media screen and (min-width: 768px) {
        grid-column: 1 / span 3;
    }
`

const VerticalCard = styled(Card)`
    @media screen and (min-width: 768px) {
        grid-column-start: 4;
        grid-row: 1 / span 2;
    }
`

const ProjectsPage = () => {
    return (
        <PageContainer>
            <ProjectGrid>
                <HorizontalCard to='freeplay-music'>
                    <h1>Freeplay Music</h1>
                    <p>
                        My largest project to date; this cross-platform app for iOS and Android was created with Flutter and utilises
                        the YoutubeExplodeDart API, alongside my own SoundCloud API, to allow users to play, save, and download music from
                        both YouTube and SoundCloud in one intuitive interface. Oh, and did I mention it was free?
                    </p>
                </HorizontalCard>
                <VerticalCard>
                    <h1>SoundCloud API</h1>
                    <p>
                        Written in Dart, this API can scrape track, playlist, album, or author metadata from the SoundCloud website,
                        including HLS and stream manifests, enabling playback or download of tracks without ever creating
                        an account or needing an API key, and without rate limits.
                    </p>
                </VerticalCard>
                <Card>
                    <h1>Volume Control Extension</h1>
                    <p>
                        A cross-platform browser extension that supports both Firefox and Chrome using Mozilla's browser polyfill
                        library, and enables users to change the relative volume of individual tabs, rather than that of the browser as
                        a whole.
                    </p>
                </Card>
                <Card>
                    <h1>This Website</h1>
                    <p>
                        The website you're looking at right now has been built entirely from scratch using GatsbyJS and styled-components,
                        and conforms to accessibility requirements through the use of HTML semantic elements, and is backwards compatible
                        with older browsers.
                    </p>
                </Card>
                <Card>
                    <h1>Much More!</h1>
                    <p>
                        Most apps and APIs that I haven't mentioned here are available on my GitHub, with many more to come in
                        the foreseeable future!
                    </p>
                </Card>
            </ProjectGrid>
        </PageContainer>
    )
}

export default ProjectsPage

export const Head = () => <title>Curtis Caulfield &mdash; Projects</title>